+import { Request, Response } from "express";
+import { TaskStatus } from "@prisma/client";
+import { z } from "zod";
+import { prisma } from "../config/prisma";
+
+const createTaskSchema = z.object({
+  projectId: z.string().uuid(),
+  title: z.string().min(2),
+  description: z.string().optional(),
+  dueDate: z.string().datetime().optional(),
+  assignedToId: z.string().uuid().optional()
+});
+
+const updateTaskSchema = z.object({
+  status: z.nativeEnum(TaskStatus).optional(),
+  assignedToId: z.string().uuid().nullable().optional()
+});
+
+export async function createTask(req: Request, res: Response) {
+  const data = createTaskSchema.parse(req.body);
+  const task = await prisma.task.create({
+    data: {
+      title: data.title,
+      description: data.description,
+      dueDate: data.dueDate ? new Date(data.dueDate) : undefined,
+      projectId: data.projectId,
+      createdById: req.user!.id,
+      assignedToId: data.assignedToId
+    }
+  });
+  return res.status(201).json(task);
+}
+
+export async function updateTask(req: Request, res: Response) {
+  const data = updateTaskSchema.parse(req.body);
+  const task = await prisma.task.update({
+    where: { id: req.params.taskId },
+    data
+  });
+  return res.json(task);
+}
+
+export async function listTasks(req: Request, res: Response) {
+  const projectId = req.query.projectId as string | undefined;
+  const tasks = await prisma.task.findMany({
+    where: projectId ? { projectId } : undefined,
+    include: {
+      assignedTo: { select: { id: true, name: true, email: true } },
+      project: { select: { id: true, name: true } }
+    },
+    orderBy: { createdAt: "desc" }
+  });
+  return res.json(tasks);
+}
+
+export async function getDashboard(req: Request, res: Response) {
+  const userId = req.user!.id;
+  const now = new Date();
+  const where = {
+    OR: [{ assignedToId: userId }, { createdById: userId }]
+  };
+
+  const [total, completed, pending, overdue] = await Promise.all([
+    prisma.task.count({ where }),
+    prisma.task.count({ where: { ...where, status: TaskStatus.COMPLETED } }),
+    prisma.task.count({
+      where: { ...where, status: { in: [TaskStatus.PENDING, TaskStatus.IN_PROGRESS] } }
+    }),
+    prisma.task.count({
+      where: {
+        ...where,
+        status: { not: TaskStatus.COMPLETED },
+        dueDate: { lt: now }
+      }
+    })
+  ]);
+
+  return res.json({ totalTasks: total, completedTasks: completed, pendingTasks: pending, overdueTasks: overdue });
+}
