+      }
+    }),
+    prisma.task.count({
+      where: {
+        ...baseWhere,
+        status: {
+          in: [TaskStatus.PENDING, TaskStatus.IN_PROGRESS]
+        }
+      }
+    }),
+    prisma.task.count({
+      where: {
+        ...baseWhere,
+        dueDate: { lt: now },
+        status: { not: TaskStatus.COMPLETED }
+      }
+    })
+  ]);
+
+  return {
+    totalTasks,
+    completedTasks,
+    pendingTasks,
+    overdueTasks
+  };
